.mrg-markdown {
  background: var(--mrg-semantic-color-background-canvas);
  color: var(--mrg-semantic-color-foreground-primary);
  display: grid;
  font-family: var(--mrg-semantic-font-family-prose);
  gap: var(--mrg-semantic-space-stack-md);
  line-height: var(--mrg-semantic-font-line-height-body);
  min-inline-size: 0;
}

.mrg-markdown__boundary {
  background: var(--mrg-semantic-color-status-info-background);
  border-block: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-status-info-border);
  color: var(--mrg-semantic-color-status-info-foreground);
  font-size: var(--mrg-semantic-font-size-label);
  font-weight: var(--mrg-semantic-font-weight-label);
  margin: 0;
  padding-block: var(--mrg-semantic-space-inset-xs);
}

.mrg-markdown__content {
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-markdown__content > :first-child {
  margin-block-start: 0;
}

.mrg-markdown__content > :last-child {
  margin-block-end: 0;
}

.mrg-markdown__content :where(h1, h2, h3, h4, h5, h6) {
  color: var(--mrg-semantic-color-foreground-primary);
  font-weight: var(--mrg-semantic-font-weight-heading);
  text-wrap: balance;
}

.mrg-markdown__content :where(a) {
  color: var(--mrg-semantic-color-action-foreground);
  text-decoration-thickness: var(--mrg-semantic-border-width-strong);
  text-underline-offset: var(--mrg-semantic-space-inline-xs);
}

.mrg-markdown__content :where(a:focus-visible) {
  box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
    var(--mrg-component-focus-indicator-contrast-background);
  outline: var(--mrg-component-focus-indicator-width) solid
    var(--mrg-component-focus-indicator-color);
  outline-offset: var(--mrg-component-focus-indicator-offset);
}

.mrg-markdown__content :where(pre) {
  background: var(--mrg-semantic-color-background-surface);
  border-block: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-strong);
  font-family: var(--mrg-semantic-font-family-code);
  margin: 0;
  max-inline-size: 100%;
  overflow: auto;
  padding: var(--mrg-semantic-space-inset-md);
  white-space: pre-wrap;
}

.mrg-markdown__content :where(table) {
  border-collapse: collapse;
  inline-size: 100%;
}

.mrg-markdown__content :where(th, td) {
  border-block-end: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-subtle);
  padding: var(--mrg-semantic-space-inset-sm);
  text-align: start;
}

.mrg-markdown__announcement {
  block-size: 1px;
  clip: rect(0 0 0 0);
  clip-path: inset(50%);
  inline-size: 1px;
  overflow: hidden;
  position: absolute;
  white-space: nowrap;
}

@media (prefers-reduced-motion: reduce) {
  .mrg-markdown *,
  .mrg-markdown *::before,
  .mrg-markdown *::after {
    animation-duration: 0s;
    transition-duration: 0s;
  }
}

@media (forced-colors: active) {
  .mrg-markdown,
  .mrg-markdown__boundary,
  .mrg-markdown__content :where(pre, th, td) {
    background: Canvas;
    border-color: CanvasText;
    color: CanvasText;
    forced-color-adjust: auto;
  }

  .mrg-markdown__content :where(a:focus-visible) {
    box-shadow: none;
    outline-color: Highlight;
  }
}

import "./markdown.css";

import { forwardRef, type HTMLAttributes, type ReactNode } from "react";

export interface MarkdownRenderContext {
  /** Exact consumer-supplied Markdown source passed to the rendering adapter. */
  readonly source: string;
  /** Whether the source is currently receiving incremental updates. */
  readonly streaming: boolean;
}

export interface MarkdownProps extends Omit<HTMLAttributes<HTMLElement>, "children"> {
  /** Untrusted Markdown source rendered literally unless a consumer adapter is supplied. */
  readonly source: string;
  /** Consumer-owned rendering and sanitization adapter; omission preserves safe literal text. */
  readonly render?: (context: MarkdownRenderContext) => ReactNode;
  /** Marks content busy during incremental updates without forcing announcements. */
  readonly streaming?: boolean;
  /** Adds polite streaming announcements; false removes the live region and update output. */
  readonly announceStreamingUpdates?: boolean;
  /** Adds explicit renderer ownership context; false removes that boundary copy. */
  readonly showRendererBoundary?: boolean;
  /** Localized renderer-boundary copy shown only when the boundary is enabled. */
  readonly rendererBoundaryLabel?: string;
  /** Builds the enabled streaming announcement from the current character count. */
  readonly streamingLabel?: (characterCount: number) => string;
  /** Domain-neutral content rendered when the source is empty. */
  readonly emptyFallback?: ReactNode;
}

function classes(...values: readonly (false | string | undefined)[]): string {
  return values.filter((value): value is string => Boolean(value)).join(" ");
}

export const Markdown = forwardRef<HTMLElement, MarkdownProps>(function Markdown(
  {
    source,
    render,
    streaming = false,
    announceStreamingUpdates = false,
    showRendererBoundary = false,
    rendererBoundaryLabel = "Content rendered by the consumer-provided Markdown adapter",
    streamingLabel = (characterCount) => `Markdown update, ${characterCount} characters received`,
    emptyFallback = "No content",
    className,
    ...props
  },
  ref,
) {
  const content =
    source.length === 0
      ? emptyFallback
      : render === undefined
        ? source
        : render({ source, streaming });
  return (
    <article
      {...props}
      ref={ref}
      aria-busy={streaming || undefined}
      className={classes("mrg-markdown", className)}
      data-renderer={render === undefined ? "literal-text" : "consumer-adapter"}
      data-slot="markdown"
      data-streaming={streaming || undefined}
    >
      {showRendererBoundary ? (
        <p className="mrg-markdown__boundary" data-slot="markdown-renderer-boundary">
          {rendererBoundaryLabel}
        </p>
      ) : null}
      <div className="mrg-markdown__content" data-slot="markdown-content">
        {render === undefined && source.length > 0 ? <pre>{content}</pre> : content}
      </div>
      {announceStreamingUpdates ? (
        <output
          aria-live="polite"
          className="mrg-markdown__announcement"
          data-slot="markdown-announcement"
        >
          {streaming ? streamingLabel(source.length) : ""}
        </output>
      ) : null}
    </article>
  );
});
